                      <div className="space-y-4">
                          <div style={{ display: 'flex', gap: '16px' }}><div style={{ flex: 1, background: 'rgba(15, 23, 42, 0.5)', padding: '12px', borderRadius: '16px' }}><p style={{ fontSize: '8px', color: '#475569', textTransform: 'uppercase' }}>Status</p><p style={{ fontSize: '10px', color: 'white' }}>Genesis</p></div><div style={{ flex: 1, background: 'rgba(15, 23, 42, 0.5)', padding: '12px', borderRadius: '16px' }}><p style={{ fontSize: '8px', color: '#475569', textTransform: 'uppercase' }}>Captured</p><p style={{ fontSize: '7px', color: '#818cf8' }}>{photoTakenAt ? new Date(photoTakenAt).toLocaleString() : 'N/A'}</p></div></div>
