                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="p-3 bg-indigo-600/10 text-indigo-400 rounded-xl border border-indigo-500/20"><Zap size={20}/></div>
                                        <div>
                                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Genesis Seal</p>
                                            <p className="text-xs font-bold text-white">Abundance Watermark</p>
                                        </div>
                                    </div>
                                    <button onClick={generateWatermark} disabled={isGeneratingWatermark} className="p-3 bg-slate-800 hover:bg-indigo-600 text-indigo-400 hover:text-white transition-all shadow-lg active:scale-95 border border-white/5">{isGeneratingWatermark ? <Loader2 size={18} className="animate-spin"/> : <Sparkles size={18}/>}</button>
                                </div>
