              <div className="flex p-1 bg-slate-950 rounded-2xl border border-slate-800">
                  <button onClick={() => setActiveTab('design')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'design' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}>Design</button>
                  <button onClick={() => setActiveTab('monetize')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'monetize' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}>Earn</button>
                  <button onClick={() => setActiveTab('capture')} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'capture' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-50'}`}>Photo</button>
              </div>

              {activeTab === 'design' && (
                  <div className="space-y-8 animate-fade-in">
                      <div className="space-y-4">
                          <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2"><Palette size={16} className="text-indigo-400"/> Security Layers</h3>
                          <div className="bg-slate-950 border border-slate-800 rounded-[2rem] p-6 space-y-6 shadow-inner">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="p-3 bg-indigo-600/10 text-indigo-400 rounded-xl border border-indigo-500/20"><Zap size={20}/></div>
                                        <div>
                                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Genesis Seal</p>
                                            <p className="text-xs font-bold text-white">Abundance Watermark</p>
                                        </div>
                                    </div>
                                    <button onClick={generateWatermark} disabled={isGeneratingWatermark} className="p-3 bg-slate-800 hover:bg-indigo-600 text-indigo-400 hover:text-white transition-all shadow-lg active:scale-95 border border-white/5">{isGeneratingWatermark ? <Loader2 size={18} className="animate-spin"/> : <Sparkles size={18}/>}</button>
                                </div>
                                {watermarkUrl && (
                                    <div className="space-y-4 animate-fade-in">
                                        <div className="flex items-center gap-4 bg-slate-900 rounded-2xl p-3 border border-indigo-500/20">
                                            <img src={watermarkUrl} className="w-12 h-12 rounded-lg object-contain bg-white" />
