                          <div className="grid grid-cols-2 gap-4">
                              <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-3 p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-indigo-500/50 transition-all shadow-inner group">
                                  <Upload className="text-slate-600 group-hover:text-indigo-400" size={24}/>
                                  <span className="text-[10px] font-black uppercase text-slate-500">Upload Photo</span>
                              </button>
                              <button onClick={startCamera} className="flex flex-col items-center gap-3 p-6 bg-slate-950 border border-slate-800 rounded-3xl hover:border-indigo-500/50 transition-all shadow-inner group">
                                  <Camera className="text-slate-600 group-hover:text-indigo-400" size={24}/>
                                  <span className="text-[10px] font-black uppercase text-slate-500">Camera</span>
                              </button>
                          </div>
                      </div>

                      <button onClick={handleIssueBadge} disabled={isExporting || !photo} className="w-full py-4 bg-indigo-600 hover:bg-indigo-50 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95 disabled:opacity-30">
                          {isExporting ? <Loader2 size={20} className="animate-spin mx-auto"/> : 'Generate & Issue Badge'}
                      </button>
                  </div>
              )}

              {activeTab === 'monetize' && (
                  <div className="space-y-6 animate-fade-in">
                      <div className="bg-amber-900/10 border border-amber-500/30 rounded-[2rem] p-8 space-y-6 shadow-xl">
                          <div className="flex items-center gap-3">
                              <div className="p-3 bg-amber-500 text-white rounded-2xl shadow-lg"><Award size={24}/></div>
                              <h3 className="text-lg font-black text-white italic uppercase tracking-tighter">Genesis Trust Loop</h3>
                          </div>
                          <p className="text-sm text-slate-300 leading-relaxed font-medium">To participate in the <strong>Share-to-Earn</strong> economy, you must notarize your digital identity. Early birds build trust scores that scale their dividends.</p>
                          <div className="space-y-4 pt-4">
                              <div className="flex items-start gap-3">
                                  <div className={`p-1.5 rounded-lg border ${isEarningEnabled ? 'bg-emerald-500 border-emerald-400 text-black' : 'bg-slate-800 border-slate-700 text-slate-500'}`}><Check size={14} strokeWidth={4}/></div>
                                  <div className="flex-1"><p className={`text-xs font-bold ${isEarningEnabled ? 'text-white' : 'text-slate-500'}`}>Sovereign Key Registry</p><p className="text-[10px] text-slate-500 mt-1 uppercase font-black">Local ECDSA identity verified</p></div>
                              </div>
                              <div className="flex items-start gap-3">
                                  <div className={`p-1.5 rounded-lg border ${isEarningEnabled ? 'bg-emerald-500 border-emerald-400 text-black' : 'bg-slate-800 border-slate-700 text-slate-500'}`}><Check size={14} strokeWidth={4}/></div>
                                  <div className="flex-1"><p className={`text-xs font-bold ${isEarningEnabled ? 'text-white' : 'text-slate-500'}`}>Genesis Certification</p><p className="text-[10px] text-slate-500 mt-1 uppercase font-black">Authorized for surplus earning</p></div>
                              </div>
                          </div>

                          {isEarningEnabled ? (
                              <div className="p-6 bg-emerald-900/20 border border-emerald-500/30 rounded-2xl flex flex-col items-center gap-3 animate-fade-in">
                                  <ShieldCheck className="text-emerald-500" size={32}/>
                                  <p className="text-xs font-black uppercase text-emerald-400 tracking-widest text-center">Identity Secured</p>
                                  <p className="text-[9px] text-slate-500 uppercase font-bold text-center">Your Earn/Spend ratio is now tracking.</p>
                              </div>
                          ) : (
                              <button 
                                onClick={handleProvisionMonetization}
                                disabled={isProvisioning}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95"
                              >
                                  {isProvisioning ? <Loader2 size={18} className="animate-spin"/> : <Zap size={18} fill="currentColor"/>}
                                  Join Earning Pool
                              </button>
                          )}
                      </div>
                  </div>
              )}

              {activeTab === 'capture' && (
                  <div className="space-y-8 animate-fade-in flex flex-col items-center justify-center py-10">
                      <div className="w-full aspect-square bg-slate-950 rounded-[3rem] border-2 border-indigo-500/30 overflow-hidden relative shadow-2xl">
                          {isCameraActive ? <video ref={videoRef} className="w-full h-full object-cover" autoPlay playsInline muted /> : (
                              <div className="w-full h-full flex flex-col items-center justify-center text-slate-800 gap-4"><Camera size={48} className="opacity-20" /><p className="text-[10px] font-black uppercase tracking-widest">Camera Inactive</p></div>
                          )}
                      </div>
                      <div className="flex gap-4 w-full">
                          {isCameraActive ? (
                              <><button onClick={capturePhoto} className="flex-1 py-4 bg-indigo-600 hover:bg-indigo-50 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-3"><Sparkles size={20}/> Capture</button><button onClick={stopCamera} className="p-4 bg-slate-800 hover:bg-red-600 rounded-2xl text-white transition-all shadow-lg"><X size={20}/></button></>
                          ) : <button onClick={startCamera} className="w-full py-4 bg-indigo-600 hover:bg-indigo-50 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-3"><RefreshCw size={18}/> Re-initialize Sensor</button>}
                      </div>
                  </div>
              )}
          </div>

          {/* Badge Display Area */}
          <div className="flex-1 bg-slate-950 flex flex-col items-center justify-center p-8 lg:p-12 relative overflow-y-auto scrollbar-hide">
              <div className="absolute top-10 flex bg-slate-900 border border-slate-800 p-1 rounded-xl shadow-2xl z-30">
                  <button onClick={() => setBadgeSide('front')} className={`px-6 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${badgeSide === 'front' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>Identity View</button>
                  <button onClick={() => setBadgeSide('back')} className={`px-6 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${badgeSide === 'back' ? 'bg-white text-black shadow-lg' : 'text-slate-500 hover:text-white'}`}>Verification View</button>
              </div>

              <div className="relative group perspective mt-12 mb-20">
                  <div id={badgeSide === 'front' ? 'badge-front' : 'badge-back'} className={`w-[330px] h-[495px] bg-[#020617] rounded-[2.5rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.6)] overflow-hidden relative border border-white/10 flex flex-col transition-all duration-700 ${badgeSide === 'back' ? '[transform:rotateY(180deg)]' : ''}`} style={{ transformStyle: 'preserve-3d' }}>
                      {badgeSide === 'front' ? (
                          <div className="h-full w-full flex flex-col relative animate-fade-in">
                              <div className="h-1/2 p-10 flex items-center justify-center relative">
                                  <div className="w-full aspect-square bg-slate-900 rounded-[2rem] border-4 border-slate-800 overflow-hidden shadow-2xl relative">
                                      {photo ? <img src={photo} className="w-full h-full object-cover object-[center_20%] transform scale-105" crossOrigin="anonymous"/> : <div className="w-full h-full flex flex-col items-center justify-center text-slate-600 bg-slate-950 gap-2">
                                          <ImageIcon size={32} className="opacity-20"/>
                                          <span className="text-[10px] font-bold uppercase">No Cover</span>
                                      </div>}
                                      {watermarkUrl && <div className="absolute inset-0 pointer-events-none flex items-center justify-center" style={{ opacity: watermarkOpacity }}><img src={watermarkUrl} className="w-48 h-48 object-contain mix-blend-screen" /></div>}
                                      <div className="absolute top-3 left-3">{isSecure ? <div className="px-2 py-0.5 bg-emerald-500 text-white rounded-full text-[7px] font-black uppercase flex items-center gap-1 shadow-lg border border-white/20"><ShieldCheck size={8}/> Secure</div> : <div className="px-2 py-0.5 bg-slate-800 text-slate-400 rounded-full text-[7px] font-black uppercase flex items-center gap-1 shadow-lg border border-white/5"><Upload size={8}/> Standard</div>}</div>
                                      {isEarningEnabled && <div className="absolute top-3 right-3 bg-amber-500 text-white p-1 rounded-lg shadow-lg border border-amber-400/50"><Coins size={12}/></div>}
                                  </div>
                              </div>
                              <div className="flex-1 p-10 pt-0 flex flex-col justify-between text-center relative z-10">
                                  <div className="space-y-1"><h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">{userProfile?.displayName || 'MEMBER NAME'}</h2><p className="text-indigo-400 text-xs font-black uppercase tracking-[0.3em]">Verified Resident</p></div>
                                  <div className="space-y-4">
                                      <div className="grid grid-cols-2 gap-4">
                                          <div className="bg-slate-900/50 p-3 rounded-2xl border border-white/5"><p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Status</p><p className="text-[10px] font-bold text-white uppercase">{userProfile?.isGenesisMember ? 'Genesis' : 'Resident'}</p></div>
                                          <div className="bg-slate-900/50 p-3 rounded-2xl border border-white/5 text-left overflow-hidden"><p className="text-[8px] font-black text-slate-600 uppercase tracking-widest">Anchor Node</p><div className="flex items-center gap-1 mt-0.5 text-[8px] font-mono text-indigo-200 uppercase truncate">0x{userProfile?.uid.substring(0, 8).toUpperCase()}</div></div>
                                      </div>
                                      <div className="w-full h-2 bg-gradient-to-r from-amber-500 via-indigo-500 to-purple-600 rounded-full shadow-lg shadow-indigo-500/20"></div>
                                      <div className="flex justify-between items-center px-1"><span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.4em]">Sovereign Trust Mesh</span><ShieldCheck size={14} className="text-amber-500 opacity-60" /></div>
                                  </div>
                              </div>
                          </div>
                      ) : (
                          <div className="h-full w-full flex flex-col p-10 text-center relative bg-[#020617] [transform:rotateY(180deg)] animate-fade-in">
                              <div className="space-y-2 mb-10 shrink-0"><h3 className="text-lg font-black text-white uppercase italic tracking-tighter flex items-center justify-center gap-2"><Lock size={16} className="text-indigo-400"/> Cryptographic Shard</h3><p className="text-[9px] text-slate-500 leading-relaxed font-bold uppercase tracking-widest">Identity Handshake v15.0</p></div>
                              <div className="flex-1 flex flex-col items-center justify-center"><div className="bg-white p-4 rounded-[2rem] shadow-2xl relative group"><img src={qrCodeUrl} className="w-48 h-48" alt="Identity Shard" /><div className="absolute inset-0 bg-indigo-600/5 group-hover:bg-indigo-600/10 transition-colors pointer-events-none rounded-[2rem]"></div></div><p className="text-[8px] font-mono text-slate-600 mt-6 break-all max-w-[200px] leading-tight">SHA-256_{userProfile?.certificate?.substring(10, 50)}...</p></div>
                              <div className="mt-10 space-y-6 pt-10 border-t border-white/5"><div className="flex justify-center grayscale opacity-60"><img src={barcodeUrl} className="h-10 w-full object-contain" alt="System Serial" /></div><div className="flex justify-between items-end"><div className="text-left"><p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Join Date</p><p className="text-[10px] font-mono text-white">{new Date(userProfile?.createdAt || Date.now()).toLocaleDateString()}</p></div><div className="text-right"><p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Binding ID</p><p className="text-[10px] font-mono text-white">#SYN-882-GEN</p></div></div></div>
                          </div>
