export async function calculateUserTrustScore(uid: string): Promise<TrustScore> {
    if (!db) return { score: 600, totalChecksIssued: 0, averageAmount: 0, verifiedVolume: 0, lastActivity: Date.now() };
    const q = query(collection(db, 'checks'), where('ownerId', '==', uid), where('isVerified', '==', true));
    const snap = await getDocs(q);
    const total = snap.size;
    const score = Math.min(850, 600 + (total * 5));
    return { score, totalChecksIssued: total, averageAmount: 0, verifiedVolume: 0, lastActivity: Date.now() };
}

export async function saveProjectToCloud(path: string, name: string, content: string, sessionId: string) {
    if (!db) throw new Error("Database offline");
    const fileId = btoa(sessionId + (path ? `${path}/${name}` : name)).replace(/=/g, '');
    const CHUNK_SIZE = 128000; 
    const chunks = [];
    if (content.length > CHUNK_SIZE) {
        for (let i = 0; i < content.length; i += CHUNK_SIZE) {
            chunks.push(content.substring(i, i + CHUNK_SIZE));
        }
    }
    const batch = writeBatch(db);
    const mainDocRef = doc(db, CLOUD_FILES_COLLECTION, fileId);
    const fileMeta = { userId: auth?.currentUser?.uid || 'guest', sessionId, name, fullPath: path ? `${path}/${name}` : name, isFolder: false, lastModified: Date.now(), size: content.length, isSharded: chunks.length > 0, chunkCount: chunks.length };
    if (chunks.length > 0) {
        batch.set(mainDocRef, { ...fileMeta, content: "[SHARDED_CONTENT]" }, { merge: true });
        chunks.forEach((chunk, idx) => { batch.set(doc(db, CLOUD_FILES_COLLECTION, `${fileId}_chunk_${idx}`), { data: chunk, sessionId }); });
    } else {
        batch.set(mainDocRef, { ...fileMeta, content }, { merge: true });
    }
    await batch.commit();
}

