import { 
    GoogleAuthProvider, 
    GithubAuthProvider,
    signInWithPopup, 
    linkWithPopup,
    signOut as firebaseSignOut
} from '@firebase/auth';
import type { User } from '@firebase/auth';
import { auth } from './firebaseConfig';
import { UserProfile } from '../types';

/**
 * Standard Google OAuth via Firebase
 */
export async function signInWithGoogle(): Promise<User | null> {
    if (!auth) return null;

    const provider = new GoogleAuthProvider();
    provider.addScope('https://www.googleapis.com/auth/drive.file');
    provider.addScope('https://www.googleapis.com/auth/youtube.upload'); 
    provider.addScope('https://www.googleapis.com/auth/youtube.force-ssl'); 
    provider.addScope('https://www.googleapis.com/auth/userinfo.profile');
    provider.addScope('https://www.googleapis.com/auth/userinfo.email');
    provider.addScope('https://www.googleapis.com/auth/gmail.send');

    provider.setCustomParameters({
        prompt: 'select_account'
    });

    try {
        const result = await signInWithPopup(auth, provider);
        const credential = GoogleAuthProvider.credentialFromResult(result);
        const token = credential?.accessToken;

        if (token) {
            localStorage.setItem('google_drive_token', token); 
            localStorage.setItem('token_expiry', (Date.now() + 3500 * 1000).toString());
        }

        const userSummary = {
            uid: result.user.uid,
            displayName: result.user.displayName,
            email: result.user.email,
            photoURL: result.user.photoURL,
            authMethod: 'google'
        };
        localStorage.setItem('drive_user', JSON.stringify(userSummary));

        return result.user;
    } catch (error: any) {
        handleAuthError(error);
        throw error;
    }
}

/**
 * Sovereign Key Login:
 * Authenticates the user locally using their own API keys.
 * NO data is sent to the server.
 */
export async function signInWithApiKeys(keys: { gemini: string, openai?: string, gcp?: string }): Promise<void> {
    if (!keys.gemini || keys.gemini.length < 10) {
        throw new Error("Valid Gemini API Key is required for Sovereign Entry.");
    }

    // Save keys to local vault (Browser only)
    localStorage.setItem('gemini_api_key', keys.gemini.trim());
    if (keys.openai) localStorage.setItem('openai_api_key', keys.openai.trim());
    if (keys.gcp) localStorage.setItem('gcp_api_key', keys.gcp.trim());

    const userSummary = {
        uid: `sovereign-${keys.gemini.substring(0, 8)}`,
        displayName: 'Sovereign Member',
        email: 'local@sovereign.mesh',
        photoURL: '',
        authMethod: 'apikey'
    };

    localStorage.setItem('drive_user', JSON.stringify(userSummary));
    localStorage.setItem('is_sovereign_session', 'true');

    // Force a small delay for UI feedback
    await new Promise(r => setTimeout(r, 500));
}

/**
 * Checks if the current session is a specialized judge/auditor session.
 */
export function isJudgeSession(): boolean {
    return !!localStorage.getItem('judge_access_token');
}

/**
 * Synchronous session resolver for App boot
 */
export function getSovereignSession(): { user: any, profile: UserProfile | null } {
    const data = localStorage.getItem('drive_user');
    const user = data ? JSON.parse(data) : null;

    const isSovereign = localStorage.getItem('is_sovereign_session') === 'true';
    if (isSovereign && user) {
        return { 
            user, 
            profile: {
                uid: user.uid,
                email: user.email,
                displayName: user.displayName,
                createdAt: Date.now(),
                lastLogin: Date.now(),
                subscriptionTier: 'pro', // Sovereign users are upgraded by default since they bring their own compute
                groups: [],
                coinBalance: 1000000, // Unlimited internal credits for local compute
                // Fix: Added missing properties to resolve UserProfile type error
                creditBalance: 1000000,
                sharingDividends: 0,
                lifetimeEarned: 0,
                lifetimeSpent: 0,
                geminiApiKey: localStorage.getItem('gemini_api_key') || '',
                openaiApiKey: localStorage.getItem('openai_api_key') || '',
                gcpApiKey: localStorage.getItem('gcp_api_key') || ''
            } as UserProfile
        };
    }

    return { user, profile: null };
}

/**
 * Initiates GitHub OAuth Flow using Firebase SDK
 */
export async function signInWithGitHub(): Promise<string | null> {
    if (!auth) return null;

    const provider = new GithubAuthProvider();
    provider.addScope('repo');
    provider.addScope('user');

    try {
        let result;
        if (auth.currentUser) {
            result = await linkWithPopup(auth.currentUser, provider);
        } else {
            result = await signInWithPopup(auth, provider);
        }

        const credential = GoogleAuthProvider.credentialFromResult(result);
        const token = credential?.accessToken;

        if (token) {
            localStorage.setItem('github_token', token);
            return token;
        }
        return null;
    } catch (error: any) {
        handleAuthError(error);
        throw error;
    }
}

export function clearGitHubToken() {
    localStorage.removeItem('github_token');
}

function handleAuthError(error: any) {
    console.error("Firebase Auth Error:", error);
    if (error.code === 'auth/unauthorized-domain') {
        alert("Domain Not Authorized: Add this URL to 'Authorized Domains' in Firebase Console.");
    } else if (error.code === 'auth/popup-blocked') {
        alert("Popup Blocked: Please allow popups for this site.");
    }
}

export function getDriveToken(): string | null {
    const token = localStorage.getItem('google_drive_token');
    const expiry = localStorage.getItem('token_expiry');
    if (token && expiry && Date.now() < parseInt(expiry)) {
        return token;
    }
    return null;
}

export async function connectGoogleDrive(): Promise<string> {
    const token = getDriveToken();
    if (token) return token;
    await signInWithGoogle();
    const newToken = getDriveToken();
    if (!newToken) throw new Error("Failed to obtain Google token");
    return newToken;
}

export async function signOut(): Promise<void> {
    if (auth) {
        await firebaseSignOut(auth);
    }
    localStorage.removeItem('google_drive_token');
    localStorage.removeItem('token_expiry');
    localStorage.removeItem('drive_user');
    localStorage.removeItem('github_token');
    localStorage.removeItem('judge_access_token');
    localStorage.removeItem('is_sovereign_session');
    localStorage.removeItem('gemini_api_key');
    localStorage.removeItem('openai_api_key');
    localStorage.removeItem('gcp_api_key');
    window.location.assign(window.location.origin);
}

export function getCurrentUser(): any {
    if (auth?.currentUser) return auth.currentUser;
    const { user } = getSovereignSession();
    return user;
}

