              setUserProfile(prev => {
                  if (!prev) return profile;
                  const arraysMatch = (a?: string[], b?: string[]) => {
                      if (!a || !b) return a === b;
                      if (a.length !== b.length) return false;
                      return a.every((v, i) => v === b[i]);
                  };
                  // Fix: Renamed coinBalance comparison to match types.ts
                  const hasChanged = prev.creditBalance !== profile.creditBalance || prev.subscriptionTier !== profile.subscriptionTier || !arraysMatch(prev.likedChannelIds, profile.likedChannelIds) || !arraysMatch(prev.bookmarkedChannelIds, profile.bookmarkedChannelIds);
                  return hasChanged ? profile : prev;
