                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex flex-wrap items-center gap-2 mb-1">
                                                            <span className="text-[7px] md:text-[8px] font-black uppercase tracking-widest opacity-40">[{log.time}]</span>
