                                                        <div className="inline-flex items-center gap-1 text-[8px] font-black text-slate-500 uppercase bg-black/20 px-2 py-0.5 rounded-full border border-white/5">
                                                            <Clock size={8}/> {Math.round(log.meta.latency)}ms
                                                        </div>
                                                    </div>
