                                            </div>

                                            {log.meta && (log.meta.inputTokens || log.meta.outputTokens || log.meta.postBalance !== undefined) && (
                                                <div className="mt-2 pt-2 md:mt-3 md:pt-3 border-t border-current/10 grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
                                                    {(log.meta.inputTokens || log.meta.outputTokens) && (
                                                        <div className="space-y-1">
                                                            <p className="text-[7px] font-black uppercase opacity-40 tracking-wider">Token Density</p>
                                                            <div className="flex items-center gap-2 font-mono text-[9px] font-bold">
                                                                <span title="Input" className="text-indigo-400">IN: {log.meta.inputTokens || 0}</span>
                                                                <span className="opacity-20">|</span>
                                                                <span title="Completion" className="text-emerald-400">OUT: {log.meta.outputTokens || 0}</span>
                                                            </div>
                                                        </div>
                                                    )}
                                                    {log.meta.inputSizeBytes && (
                                                        <div className="space-y-1">
                                                            <p className="text-[7px] font-black uppercase opacity-40 tracking-wider">Payload Mass</p>
                                                            <p className="font-mono text-[9px] font-bold uppercase tracking-tighter">
                                                                {Math.round(log.meta.inputSizeBytes / 1024)}KB → {Math.round((log.meta.outputSizeBytes || 0) / 1024)}KB
                                                            </p>
                                                        </div>
                                                    )}
                                                    {log.meta.postBalance !== undefined && (
                                                        <div className="space-y-1">
                                                            <p className="text-[7px] font-black uppercase opacity-40 tracking-wider">Neural Ledger (VC)</p>
                                                            <div className="flex items-center gap-1.5 font-mono text-[9px] font-black">
                                                                <span className="text-slate-400">{log.meta.preBalance}</span>
                                                                <ArrowRight size={8} className="opacity-30"/>
                                                                <span className="text-emerald-400">{log.meta.postBalance}</span>
                                                            </div>
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            </>
                        ) : consoleTab === 'loop' ? (
                            <div className="flex-1 flex flex-col min-w-0 bg-black/80 animate-fade-in">
                                <div className="px-6 py-3 border-b border-white/5 flex items-center justify-between bg-indigo-900/20">
                                    <div className="flex items-center gap-2"><Repeat size={14} className="text-indigo-400 animate-spin-slow"/><span className="text-[10px] font-black uppercase tracking-widest text-indigo-100">Dyad Self-Feedback Loop</span></div>
                                    <button onClick={handleExportLogs} className="p-1.5 text-indigo-300 hover:text-white" title="Export Loop Logs"><FileDown size={14}/></button>
                                </div>
                                <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-4 scrollbar-hide">
                                    {visibleLogs.filter(l => l.type === 'loop').length === 0 && (
                                        <div className="h-full flex flex-col items-center justify-center opacity-20 gap-4">
                                            <Repeat size={48}/>
                                            <p className="text-xs font-black uppercase tracking-widest">Awaiting Machine Handshake</p>
                                        </div>
                                    )}
                                    {visibleLogs.filter(l => l.type === 'loop').map(log => (
                                        <div key={log.id} className="bg-slate-900 border border-indigo-500/20 rounded-3xl p-4 md:p-6 space-y-4 shadow-xl">
                                            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2 border-b border-white/5 pb-3">
                                                <div className="flex items-center gap-2 md:gap-3 flex-wrap">
                                                    <span className="text-[7px] md:text-[8px] font-black text-indigo-400 uppercase bg-indigo-500/10 px-2 py-0.5 rounded">FROM: {log.meta?.senderTool}</span>
                                                    <ArrowRight size={10} className="text-slate-600"/>
                                                    <span className="text-[7px] md:text-[8px] font-black text-emerald-400 uppercase bg-emerald-500/10 px-2 py-0.5 rounded">TO: {log.meta?.receiverTool}</span>
                                                </div>
                                                <span className="text-[8px] md:text-[9px] font-mono text-slate-500">[{log.time}]</span>
                                            </div>
                                            <div className="space-y-2">
                                                <p className="text-xs text-white font-bold">{log.text}</p>
                                                <div className="bg-black rounded-2xl p-4 border border-white/5 font-mono text-[10px] text-indigo-300 overflow-x-auto">
                                                    <pre className="break-words whitespace-pre-wrap">{safeJsonStringify(log.meta?.machineContent)}</pre>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col p-6 md:p-8 space-y-6 animate-fade-in">
                                <div className="flex justify-between items-center"><h3 className="text-lg font-black text-white italic uppercase tracking-widest flex items-center gap-3"><MessageCircle className="text-indigo-400"/> Human Feedback</h3>{feedbackSuccess && (<div className="flex items-center gap-2 text-emerald-400 text-[10px] font-black uppercase bg-emerald-950/30 px-3 py-1.5 rounded-lg border border-emerald-500/30 animate-fade-in"><CheckCircle size={14}/> {t.feedbackSuccess}</div>)}</div>
                                <div className="grid grid-cols-3 gap-2">
                                    {(['general', 'bug', 'feature'] as const).map(type => (
                                        <button key={type} onClick={() => setFeedbackType(type)} className={`py-2 rounded-xl text-[10px] font-black uppercase border transition-all ${feedbackType === type ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-900 border-slate-800 text-slate-50'}`}>{type}</button>
                                    ))}
                                </div>
                                <textarea value={feedbackText} onChange={e => setFeedbackText(e.target.value)} className="flex-1 bg-slate-950 border border-slate-800 rounded-[2rem] p-6 text-sm text-slate-300 outline-none focus:ring-2 focus:ring-indigo-500/50 resize-none shadow-inner leading-relaxed" placeholder="Report a bug, suggest a feature, or request a new Neural Lab..."/>
                                <div className="flex flex-col sm:flex-row justify-between items-center gap-4"><div className="flex items-center gap-2 px-4 py-2 bg-slate-950 border border-slate-800 rounded-full text-[9px] font-black text-slate-500 uppercase"><Activity size={12} className="text-indigo-400"/> Trace Bundling Enabled</div><button onClick={handleSendFeedback} disabled={!feedbackText.trim() || isSubmittingFeedback} className="w-full sm:w-auto px-10 py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-black uppercase tracking-widest rounded-2xl shadow-xl transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-3">{isSubmittingFeedback ? <Loader2 size={18} className="animate-spin"/> : <Send size={18}/>}<span>{t.submitFeedback}</span></button></div>
                            </div>
                        )}
                    </div>
                </div>
                <div className="bg-black/90 p-2 text-center border-t border-white/5"><p className="text-[8px] font-black text-slate-700 uppercase tracking-[0.4em]">Neural Handshake Protocol v12.9.5-TELEMETRY</p></div>
            </div>
        </div>

        <CreateChannelModal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} onCreate={handleCreateChannel} currentUser={currentUser} />
        <VoiceCreateModal isOpen={isVoiceCreateOpen} onClose={() => setIsVoiceCreateOpen(false)} onCreate={handleCreateChannel} />
        <PricingModal isOpen={isPricingModalOpen} onClose={() => setIsPricingModalOpen(false)} user={userProfile} onSuccess={(tier) => { if(userProfile) setUserProfile({...userProfile, subscriptionTier: tier}); }} />
        {currentUser && ( <SettingsModal isOpen={isSettingsModalOpen} onClose={() => setIsSettingsModalOpen(false)} user={userProfile || { uid: currentUser.uid, email: currentUser.email, displayName: currentUser.displayName, photoURL: currentUser.photoURL, groups: [], coinBalance: 0, creditBalance: 0, sharingDividends: 0, lifetimeEarned: 0, lifetimeSpent: 0, createdAt: Date.now(), lastLogin: Date.now(), subscriptionTier: 'free', apiUsageCount: 0 } as UserProfile} onUpdateProfile={setUserProfile} onUpgradeClick={() => setIsPricingModalOpen(true)} isSuperAdmin={isSuperAdmin} onNavigateAdmin={() => handleSetViewState('firestore_debug')} /> )}

        {commentChannelId && ( <CommentsModal isOpen={true} onClose={() => setCommentChannelId(null)} channel={commentChannel!} onAddComment={handleAddComment} onDeleteComment={handleDeleteComment} onEditComment={handleEditComment} currentUser={currentUser} /> )}
        {editChannelId && ( <ChannelSettingsModal isOpen={true} onClose={() => setEditChannelId(null)} channel={editChannel!} onUpdate={handleUpdateChannel} /> )}

        {manualViewId && ( <ManualModal isOpen={true} onClose={() => setManualViewId(null)} viewId={manualViewId} /> )}
      </div>
    </ErrorBoundary>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Bell, Check, X, Loader2, Users, Calendar, Link, ExternalLink, Coins, MessageSquare, Receipt } from 'lucide-react';
// Fix: Added missing Firestore exports
import { getPendingInvitations, respondToInvitation, getPendingBookings, respondToBooking, subscribeToReceipts, confirmReceipt, claimReceipt } from '../services/firestoreService';
import { Invitation, Booking, DigitalReceipt } from '../types';
import { auth } from '../services/firebaseConfig';
/* Fix: Standardized Firebase modular imports */
import { onAuthStateChanged } from '@firebase/auth';

export const Notifications: React.FC = () => {
  const [invites, setInvites] = useState<Invitation[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [receipts, setReceipts] = useState<DigitalReceipt[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [user, setUser] = useState<any>(auth?.currentUser);

  const dispatchLog = useCallback((text: string, type: 'info' | 'success' | 'warn' | 'error' = 'info') => {
      window.dispatchEvent(new CustomEvent('neural-log', { 
          detail: { text: `[Notifications] ${text}`, type } 
      }));
  }, []);

  useEffect(() => {
    if (!auth) return;
    return onAuthStateChanged(auth, (u) => {
      setUser(u);
    });
  }, []);

  const fetchData = async () => {
    if (!user) return;
    try {
      const [invData, bookData] = await Promise.all([
          getPendingInvitations(user.uid, user.email || ''),
          getPendingBookings(user.uid, user.email || '')
      ]);
      setInvites(invData);
      setBookings(bookData);

      if (invData.length > 0 || bookData.length > 0) {
          dispatchLog(`Audit: Found ${invData.length} Invites, ${bookData.length} Bookings.`, 'info');
      }
    } catch (e) {
      console.error("Failed to fetch notifications", e);
    }
  };

  useEffect(() => {
    if (user) {
      fetchData();
      const unsubReceipts = subscribeToReceipts(user.uid, (data) => {
          setReceipts(data);
          if (data.length > 0) {
              dispatchLog(`Ledger Update: ${data.length} receipts synced from cloud.`, 'info');
          }
      });
      const interval = setInterval(fetchData, 30000);
      return () => {
          clearInterval(interval);
          unsubReceipts();
      };
    } else {
      setInvites([]);
      setBookings([]);
      setReceipts([]);
    }
  }, [user, dispatchLog]);

  // Sync totalCount logic with actual filtering in render
  const actionableReceipts = useMemo(() => {
      if (!user) return [];
      return receipts.filter(r => {
          const isSender = r.senderId === user.uid;
          const canConfirm = !isSender && r.status === 'pending';
          const canClaim = isSender && r.status === 'confirmed';
          return canConfirm || canClaim;
      });
  }, [receipts, user]);

  const totalCount = invites.length + bookings.length + actionableReceipts.length;

  const handleRespondInvite = async (invitation: Invitation, accept: boolean) => {
    setProcessingId(invitation.id);
    try {
      // Fix: changed 'coin' check to 'credit' to match Invitation type and resolve type comparison error
      if (invitation.type === 'credit') {
          await respondToInvitation(invitation, accept);
          setInvites(prev => prev.filter(i => i.id !== invitation.id));
          if (accept) {
              window.dispatchEvent(new CustomEvent('neural-log', { detail: { text: "Coins claimed. Ledger updated.", type: 'success' } }));
          }
      } else if (invitation.type === 'session') {
          await respondToInvitation(invitation, accept);
          setInvites(prev => prev.filter(i => i.id !== invitation.id));
          if (accept && invitation.link) window.open(invitation.link, '_blank');
      } else {
          await respondToInvitation(invitation, accept);
          setInvites(prev => prev.filter(i => i.id !== invitation.id));
          if (accept) {
             window.location.reload();
          }
      }
    } catch (e: any) {
      alert("Error: " + (e.message || "Unknown error"));
    } finally {
      setProcessingId(null);
    }
  };

  const handleConfirm = async (id: string) => {
      setProcessingId(id);
      try {
          await confirmReceipt(id);
          window.dispatchEvent(new CustomEvent('neural-log', { detail: { text: "Payment authorized.", type: 'success' } }));
      } catch (e: any) {
          alert(e.message);
      } finally {
          setProcessingId(null);
      }
  };

  const handleClaim = async (id: string) => {
      setProcessingId(id);
      try {
          await claimReceipt(id);
          window.dispatchEvent(new CustomEvent('neural-log', { detail: { text: "Funds claimed successfully!", type: 'success' } }));
      } catch (e: any) {
          alert(e.message);
      } finally {
          setProcessingId(null);
      }
  };

  if (!user) return null;

  return (
    <div className="relative">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="relative p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
      >
        <Bell size={20} />
        {totalCount > 0 && (
          <span className="absolute top-1 right-1 w-4 h-4 bg-red-500 rounded-full animate-pulse border border-slate-900 text-[10px] flex items-center justify-center text-white font-bold">
              {totalCount}
          </span>
        )}
      </button>

      {isOpen && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setIsOpen(false)}></div>
          <div className="absolute right-0 mt-2 w-80 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-50 overflow-hidden animate-fade-in-up">
            <div className="p-3 border-b border-slate-800 bg-slate-950/50 flex justify-between items-center">
               <h3 className="text-sm font-bold text-white">Notifications</h3>
               {totalCount > 0 && <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">{totalCount} Actionable</span>}
            </div>

            <div className="max-h-96 overflow-y-auto">
               {totalCount === 0 ? (
                 <div className="p-8 text-center text-slate-500 text-sm italic">
                    No pending activities.
                 </div>
               ) : (
                 <div className="divide-y divide-slate-800">

                    {/* MEETING REQUESTS */}
                    {bookings.map(booking => (
                        <div key={booking.id} className="p-4 hover:bg-slate-800/30 transition-colors border-l-2 border-blue-500">
                            <div className="flex items-start space-x-3">
                                <div className="p-2 bg-blue-900/30 rounded-full text-blue-400 shrink-0">
                                    <Calendar size={16} />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm text-slate-200">
                                        <span className="font-bold">{booking.hostName}</span> wants to meet.
                                    </p>
                                    <p className="text-[10px] text-indigo-300 font-bold mt-1 truncate">{booking.topic}</p>
                                    <div className="flex gap-2 mt-3">
                                        <button onClick={() => respondToBooking(booking.id, true)} className="flex-1 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-[10px] font-bold rounded">Accept</button>
                                        <button onClick={() => respondToBooking(booking.id, false)} className="flex-1 py-1.5 bg-slate-800 text-slate-400 rounded border border-slate-700 text-[10px]">Decline</button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}

                    {/* DIGITAL RECEIPTS (ACTIONABLE ONLY) */}
                    {actionableReceipts.map(r => {
                        const isSender = r.senderId === user.uid;
                        const canConfirm = !isSender && r.status === 'pending';
                        const canClaim = isSender && r.status === 'confirmed';

                        return (
                            <div key={r.id} className={`p-4 hover:bg-slate-800/30 transition-colors border-l-2 ${canClaim ? 'border-emerald-500' : 'border-indigo-500'}`}>
                                <div className="flex items-start space-x-3">
                                    <div className={`p-2 rounded-full shrink-0 ${canClaim ? 'bg-emerald-900/30 text-emerald-400' : 'bg-indigo-900/30 text-indigo-400'}`}>
                                        <Receipt size={16} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-sm text-slate-200">
                                            {isSender ? (
                                                <><span className="font-bold">{r.receiverName}</span> confirmed your <span className="text-emerald-400 font-bold">{r.amount} VC</span> request!</>
                                            ) : (
                                                <><span className="font-bold">{r.senderName}</span> requested <span className="text-indigo-400 font-bold">{r.amount} VC</span></>
                                            )}
                                        </p>
                                        {r.memo && <p className="text-[10px] text-slate-500 mt-1 italic truncate">"{r.memo}"</p>}
                                        <div className="flex gap-2 mt-3">
                                            {canConfirm && (
                                                <button 
                                                    onClick={() => handleConfirm(r.id)} 
                                                    disabled={processingId === r.id}
                                                    className="flex-1 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-[10px] font-bold rounded shadow-lg flex items-center justify-center"
                                                >
                                                    {processingId === r.id ? <Loader2 size={12} className="animate-spin"/> : 'Authorize Payment'}
                                                </button>
                                            )}
                                            {canClaim && (
                                                <button 
                                                    onClick={() => handleClaim(r.id)} 
                                                    disabled={processingId === r.id}
                                                    className="flex-1 py-1.5 bg-emerald-600 hover:bg-emerald-500 text-white text-[10px] font-bold rounded shadow-lg flex items-center justify-center"
                                                >
                                                    {processingId === r.id ? <Loader2 size={12} className="animate-spin"/> : 'Claim Funds'}
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}

                    {/* COIN INVITES & GROUP INVITES */}
                    {invites.map(invite => (
                        // Fix: Corrected type check from 'coin' to 'credit' to resolve type comparison error
                       <div key={invite.id} className={`p-4 hover:bg-slate-800/30 transition-colors border-l-2 ${invite.type === 'credit' ? 'border-amber-500' : 'border-indigo-500'}`}>
                          <div className="flex items-start space-x-3">
                             <div className={`p-2 rounded-full shrink-0 ${invite.type === 'credit' ? 'bg-amber-900/30 text-amber-400' : 'bg-indigo-900/30 text-indigo-400'}`}>
                                {invite.type === 'credit' ? <Coins size={16} /> : <Users size={16} />}
                             </div>
                             <div className="flex-1 min-w-0">
                                {invite.type === 'credit' ? (
                                    <>
                                        <p className="text-sm text-slate-200">
                                            <span className="font-bold">{invite.fromName}</span> sent you <span className="text-amber-400 font-bold">{invite.amount} VoiceCoins</span>!
                                        </p>
                                        <button 
                                            onClick={() => handleRespondInvite(invite, true)}
                                            disabled={processingId === invite.id}
                                            className="w-full mt-3 py-1.5 bg-amber-600 hover:bg-amber-500 text-white text-[10px] font-bold rounded shadow-lg flex items-center justify-center gap-2"
                                        >
                                            {processingId === invite.id ? <Loader2 size={12} className="animate-spin"/> : <Check size={12}/>}
                                            Claim Coins
                                        </button>
                                    </>
                                ) : (
                                    <>
                                        <p className="text-sm text-slate-200">
                                            <span className="font-bold">{invite.fromName}</span> invited you to {invite.type === 'session' ? 'collaborate' : 'join'}: <span className="font-bold text-indigo-300">{invite.groupName}</span>.
                                        </p>
                                        <div className="flex space-x-2 mt-3">
                                            <button onClick={() => handleRespondInvite(invite, true)} className="flex-1 py-1.5 bg-indigo-600 text-white text-[10px] font-bold rounded">Join</button>
                                            <button onClick={() => handleRespondInvite(invite, false)} className="flex-1 py-1.5 bg-slate-800 text-slate-400 rounded border border-slate-700 text-[10px]">Ignore</button>
                                        </div>
                                    </>
                                )}
                             </div>
                          </div>
                       </div>
                    ))}
                 </div>
               )}
            </div>
          </div>
        </>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { 
  ArrowUpRight, ArrowDownLeft, RefreshCw, Send, 
  QrCode, Copy, Check, Loader2, History, Wallet, 
  ArrowLeft, Search, AlertCircle, Info, ShieldCheck,
  Zap, TrendingUp, CreditCard, ExternalLink, Smartphone, 
  Clock, CheckCircle, Database, Activity
} from 'lucide-react';
import { UserProfile, CreditTransaction } from '../types';
import { getCoinTransactions, transferCoins, getUserProfile } from '../services/firestoreService';
import { auth } from '../services/firebaseConfig';

interface CoinWalletProps {
  onBack: () => void;
  user: UserProfile | null;
  onOpenManual?: () => void;
}

export const CoinWallet: React.FC<CoinWalletProps> = ({ onBack, user, onOpenManual }) => {
  const [activeTab, setActiveTab] = useState<'history' | 'send' | 'receive'>('history');
  const [transactions, setTransactions] = useState<CreditTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [copyStatus, setCopyStatus] = useState(false);

  // Allocation State
  const [recipientId, setRecipientId] = useState('');
  const [recipientEmail, setRecipientEmail] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [memo, setMemo] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [transferSuccess, setTransferSuccess] = useState(false);

  const currentUser = auth?.currentUser;

  const loadData = useCallback(async () => {
    if (!currentUser) return;
    setIsRefreshing(true);
    try {
      const data = await getCoinTransactions(currentUser.uid) as any;
      setTransactions(data);
    } catch (e) {
      console.error("Ledger sync failed", e);
    } finally {
      setLoading(false);
      setIsRefreshing(false);
    }
  }, [currentUser]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const handleCopyAddress = () => {
    if (!currentUser) return;
    navigator.clipboard.writeText(currentUser.uid);
    setCopyStatus(true);
    setTimeout(() => setCopyStatus(false), 2000);
  };

  const handleTransfer = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !amount || isProcessing) return;

    const numAmount = parseFloat(amount);
    if (isNaN(numAmount) || numAmount <= 0) {
      alert("Invalid amount");
      return;
    }

    if (numAmount > (user?.creditBalance || 0)) {
      alert("Insufficient compute credits for this refraction.");
      return;
    }

    setIsProcessing(true);
    try {
      await transferCoins(
        recipientId || 'unknown',
        'Node', 
        recipientEmail,
        numAmount,
        memo || 'Neural Mesh Allocation'
      );

      setTransferSuccess(true);
      setAmount('');
      setRecipientEmail('');
      setRecipientId('');
      setMemo('');

      loadData();

      setTimeout(() => setTransferSuccess(false), 5000);
    } catch (e: any) {
      alert("Allocation Refused: " + e.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const qrCodeUrl = useMemo(() => {
    if (!currentUser) return '';
    return `https://api.qrserver.com/v1/create-qr-code/?size=300x300&bgcolor=ffffff&data=${encodeURIComponent(currentUser.uid)}`;
  }, [currentUser]);

  return (
    <div className="h-full flex flex-col bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <header className="h-16 border-b border-slate-800 bg-slate-900/50 flex items-center justify-between px-6 backdrop-blur-md shrink-0 z-20">
          <div className="flex items-center gap-4">
              <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 transition-colors">
                <ArrowLeft size={20} />
              </button>
              <div>
                <h1 className="text-lg font-bold text-white flex items-center gap-2 uppercase tracking-tighter italic">
                    <Database className="text-amber-400" /> 
                    Neural Ledger
                </h1>
                <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest">Compute Shards & Reputation Index</p>
              </div>
          </div>
          <div className="flex items-center gap-3">
              <button 
                onClick={loadData} 
                className="p-2 text-slate-500 hover:text-white transition-all"
                title="Sync Registry"
              >
                <RefreshCw size={18} className={isRefreshing ? 'animate-spin' : ''} />
              </button>
              {onOpenManual && <button onClick={onOpenManual} className="p-2 text-slate-400 hover:text-white" title="Ledger Manual"><Info size={18}/></button>}
          </div>
      </header>

      <div className="flex-1 overflow-y-auto p-6 md:p-8 scrollbar-hide">
        <div className="max-w-4xl mx-auto space-y-8 animate-fade-in-up">

          {/* Main Balance Card */}
          <div className="bg-gradient-to-br from-indigo-500 to-indigo-800 rounded-[2.5rem] p-10 shadow-2xl shadow-indigo-900/20 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-32 bg-white/10 blur-[100px] rounded-full group-hover:scale-110 transition-transform duration-1000"></div>
              <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-8">
                  <div className="space-y-2 text-center md:text-left">
                      <p className="text-indigo-100/60 text-xs font-black uppercase tracking-[0.3em]">Compute Allocation</p>
                      <div className="flex items-center gap-4 justify-center md:justify-start">
                        <h2 className="text-6xl font-black text-white tracking-tighter tabular-nums">
                            {user?.creditBalance?.toLocaleString() || '0'}
                        </h2>
                        <span className="text-2xl font-black text-indigo-200/80 italic tracking-tighter">AC</span>
                      </div>
                  </div>
                  <div className="flex gap-3">
                      <button onClick={() => setActiveTab('send')} className="px-8 py-4 bg-white text-indigo-800 font-black uppercase tracking-widest rounded-2xl shadow-xl hover:scale-105 transition-all active:scale-95 text-xs">Dispatch</button>
                      <button onClick={() => setActiveTab('receive')} className="px-8 py-4 bg-black/20 text-white font-black uppercase tracking-widest rounded-2xl border border-white/20 hover:bg-black/30 transition-all active:scale-95 text-xs">Verify</button>
                  </div>
              </div>
          </div>

          <div className="flex bg-slate-900 p-1 rounded-2xl border border-slate-800 shadow-xl max-w-sm mx-auto">
              <button onClick={() => setActiveTab('history')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}>History</button>
              <button onClick={() => setActiveTab('send')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'send' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-50'}`}>Allocate</button>
              <button onClick={() => setActiveTab('receive')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'receive' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-50'}`}>Node URI</button>
          </div>

          {activeTab === 'history' && (
              <div className="space-y-4 animate-fade-in">
                  <div className="flex items-center justify-between px-2">
                    <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                        <History size={14} className="text-indigo-400"/> Audit Logs
                    </h3>
                  </div>

                  {loading ? (
                      <div className="py-20 flex flex-col items-center gap-4 text-indigo-400">
                          <Loader2 className="animate-spin" size={32}/>
                          <p className="text-[10px] font-black uppercase tracking-widest">Paging Ledger...</p>
                      </div>
                  ) : transactions.length === 0 ? (
                      <div className="py-20 flex flex-col items-center justify-center text-slate-700 bg-slate-900/20 rounded-[2.5rem] border-2 border-dashed border-slate-800 gap-4">
                          <Activity size={48} className="opacity-10"/>
                          <p className="text-sm font-bold uppercase tracking-widest">No mesh activity recorded</p>
                      </div>
                  ) : (
                      <div className="grid grid-cols-1 gap-3">
                          {transactions.map(tx => (
                              <div key={tx.id} className="bg-slate-900 border border-slate-800 p-5 rounded-[2rem] flex items-center justify-between hover:border-indigo-500/30 transition-all group">
                                  <div className="flex items-center gap-5">
                                      <div className={`p-3 rounded-2xl ${tx.fromId === currentUser?.uid ? 'bg-red-900/20 text-red-400' : 'bg-emerald-900/20 text-emerald-400'}`}>
                                          {tx.fromId === currentUser?.uid ? <ArrowUpRight size={20}/> : <ArrowDownLeft size={20}/>}
                                      </div>
                                      <div>
                                          <h4 className="font-bold text-white uppercase tracking-tight">
                                              {tx.fromId === currentUser?.uid ? `Allocated to ${tx.toName}` : `Received from ${tx.fromName}`}
                                          </h4>
                                          <div className="flex items-center gap-3 mt-1 text-[10px] text-slate-500 uppercase font-black">
                                              <span className="flex items-center gap-1"><Clock size={12}/> {new Date(tx.timestamp).toLocaleDateString()}</span>
                                              <span className="flex items-center gap-1"><Database size={12}/> {tx.type}</span>
                                          </div>
                                          {tx.memo && <p className="text-[10px] text-slate-600 mt-2 italic line-clamp-1">"{tx.memo}"</p>}
                                      </div>
                                  </div>
                                  <div className="text-right">
                                      <p className={`text-xl font-black tracking-tighter ${tx.fromId === currentUser?.uid ? 'text-red-400' : 'text-emerald-400'}`}>
                                          {tx.fromId === currentUser?.uid ? '-' : '+'}{tx.amount.toLocaleString()}
                                      </p>
                                      {tx.isVerified && (
                                          <div className="flex items-center justify-end gap-1 mt-1 text-indigo-400">
                                              <ShieldCheck size={10}/>
                                              <span className="text-[8px] font-black uppercase">Notarized</span>
                                          </div>
                                      )}
                                  </div>
                              </div>
                          ))}
                      </div>
                  )}
              </div>
          )}

          {activeTab === 'send' && (
              <div className="max-w-xl mx-auto w-full animate-fade-in-up">
                  <form onSubmit={handleTransfer} className="bg-slate-900 border border-slate-800 rounded-[3rem] p-10 shadow-2xl space-y-8 relative overflow-hidden">
                      <div className="absolute top-0 right-0 p-16 bg-indigo-500/5 blur-3xl rounded-full"></div>

                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">Target Node URI / Email</label>
                        <input 
                            required
                            type="text" 
                            placeholder="member@email.com or UID..." 
                            className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 text-white focus:ring-2 focus:ring-indigo-500 outline-none shadow-inner"
                            value={recipientEmail}
                            onChange={e => setRecipientEmail(e.target.value)}
                        />
                      </div>

                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">Compute Mass (AC)</label>
                        <div className="relative">
                            <input 
                                required
                                type="number" 
                                placeholder="0.00" 
                                className="w-full bg-slate-950 border border-slate-800 rounded-2xl pl-12 pr-6 py-5 text-2xl font-black text-white focus:ring-2 focus:ring-indigo-500 outline-none shadow-inner"
                                value={amount}
                                onChange={e => setAmount(e.target.value)}
                            />
                            <Zap className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-500" size={24}/>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">Neural Memo</label>
                        <textarea 
                            rows={3}
                            placeholder="Reason for allocation..." 
                            className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-4 text-sm text-slate-300 focus:ring-2 focus:ring-indigo-500 outline-none resize-none shadow-inner"
                            value={memo}
                            onChange={e => setMemo(e.target.value)}
                        />
                      </div>

                      {transferSuccess ? (
                          <div className="p-6 bg-emerald-900/20 border border-emerald-500/30 rounded-2xl flex flex-col items-center gap-3 animate-fade-in">
                              <CheckCircle className="text-emerald-500" size={32}/>
                              <p className="text-sm font-bold text-emerald-400 uppercase tracking-widest">Allocation Finalized</p>
                          </div>
                      ) : (
                          <button 
                            type="submit" 
                            disabled={isProcessing || !amount || !recipientEmail}
                            className="w-full py-5 bg-indigo-600 hover:bg-indigo-50 text-white font-black uppercase tracking-[0.2em] rounded-[2rem] shadow-2xl shadow-indigo-900/40 transition-all active:scale-95 disabled:opacity-30 flex items-center justify-center gap-3"
                          >
                            {isProcessing ? <Loader2 className="animate-spin" size={24}/> : <Zap size={20} fill="currentColor"/>}
                            <span>Execute Allocation</span>
                          </button>
                      )}
                  </form>
              </div>
          )}

          {activeTab === 'receive' && (
              <div className="max-w-xl mx-auto w-full animate-fade-in-up">
                  <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] p-12 text-center shadow-2xl space-y-10 relative overflow-hidden">
                      <div className="absolute top-0 left-0 p-24 bg-indigo-500/5 blur-[80px] rounded-full"></div>

                      <div className="space-y-2">
                        <h2 className="text-2xl font-black text-white italic uppercase tracking-tighter">Your Public Node URI</h2>
                        <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em]">Scan to initiate neural handshake</p>
                      </div>

                      <div className="bg-white p-8 rounded-[3rem] shadow-2xl relative inline-block group">
                          <div className="absolute inset-0 bg-indigo-600/5 group-hover:bg-indigo-600/10 transition-colors pointer-events-none rounded-[3rem]"></div>
                          <img src={qrCodeUrl} className="w-48 h-48" alt="Node QR" />
                      </div>

                      <div className="space-y-4">
                          <div className="bg-slate-950 border border-slate-800 rounded-2xl p-4 flex items-center justify-between shadow-inner">
                              <code className="text-[10px] font-mono text-indigo-300 truncate max-w-[200px]">{currentUser?.uid}</code>
                              <button onClick={handleCopyAddress} className="p-2 hover:bg-slate-800 rounded-xl text-slate-500 hover:text-white transition-all">
                                  {copyStatus ? <Check size={18} className="text-emerald-400"/> : <Copy size={18}/>}
                              </button>
                          </div>
                          <p className="text-[9px] text-slate-600 font-black uppercase tracking-widest leading-relaxed">
                              This is your sovereign node identifier. Shared nodes can allocate compute credits directly to your ledger.
                          </p>
                      </div>
                  </div>
              </div>
          )}

        </div>
      </div>

      <footer className="p-4 text-center border-t border-slate-800 bg-slate-950 shrink-0">
          <p className="text-[9px] font-black text-slate-700 uppercase tracking-[0.5em]">Neural Ledger Stability: 100.0% // RMP Compliant</p>
      </footer>
    </div>
  );
};

