  const [liveSessionParams, setLiveSessionParams] = useState<any>(null);

  const handleDetailBack = useCallback(() => {
    handleSetViewState('directory');
  }, [handleSetViewState]);

  const handleStartLiveSession = useCallback((
    channel: Channel, 
    context?: string, 
    recordingEnabled?: boolean, 
