    if (snap.exists()) {
        const data = snap.data() as any;
        if (data.isSharded) {
            let content = '';
            for (let i = 0; i < data.chunkCount; i++) {
                const chunkSnap = await getDoc(doc(db, CLOUD_FILES_COLLECTION, `${fileId}_chunk_${idx}`));
                if (chunkSnap.exists()) content += (chunkSnap.data() as any).data;
