export async function createOrGetDMChannel(otherUid: string, otherName: string): Promise<string> {
    if (!db || !auth.currentUser) return '';
    const myUid = auth.currentUser.uid;
    const channelId = [myUid, otherUid].sort().join('_');
    const ref = doc(db, 'chat_channels', channelId);
    const snap = await getDoc(ref);
    if (!snap.exists()) {
        await setDoc(ref, { id: channelId, name: `${auth.currentUser.displayName} & ${otherName}`, type: 'dm', memberIds: [myUid, otherUid], createdAt: Date.now() });
    }
    return channelId;
}

