export async function followUser(myUid: string, targetUid: string) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        tx.update(doc(db, USERS_COLLECTION, myUid), { following: arrayUnion(targetUid) });
        tx.update(doc(db, USERS_COLLECTION, targetUid), { followers: arrayUnion(myUid) });
    });
}

export async function unfollowUser(myUid: string, targetUid: string) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        tx.update(doc(db, USERS_COLLECTION, myUid), { following: arrayRemove(targetUid) });
        tx.update(doc(db, USERS_COLLECTION, targetUid), { followers: arrayRemove(myUid) });
    });
}

