export async function respondToInvitation(invitation: Invitation, accept: boolean): Promise<void> {
    if (!db || !auth.currentUser) return;
    await updateDoc(doc(db, 'invitations', invitation.id), { status: accept ? 'accepted' : 'rejected' });
    if (accept && invitation.type === 'group' && invitation.groupId) {
        await joinGroup(invitation.groupId);
    }
}

// Fix: added seedDatabase to resolve compilation error on line 2 of PublicChannelInspector.tsx
export async function seedDatabase(): Promise<void> {
    if (!db) return;
    const batch = writeBatch(db);
    HANDCRAFTED_CHANNELS.forEach(c => {
        batch.set(doc(db, CHANNELS_COLLECTION, c.id), sanitizeData(c));
    });
    await batch.commit();
}

// Fix: added uploadFileToStorage to resolve compilation error on line 5 of CommentsModal.tsx
export async function uploadFileToStorage(path: string, file: File | Blob): Promise<string> {
    if (!storage) throw new Error("Storage unavailable");
    const fileRef = ref(storage, path);
    await uploadBytes(fileRef, file);
    return await getDownloadURL(fileRef);
}

// Fix: added getUserBookings to resolve compilation error on line 6 of CalendarView.tsx
export async function getUserBookings(uid: string, email: string): Promise<Booking[]> {
    if (!db) return [];
    const q1 = query(collection(db, 'bookings'), where('userId', '==', uid));
    const q2 = query(collection(db, 'bookings'), where('invitedEmail', '==', email));
    const [s1, s2] = await Promise.all([getDocs(q1), getDocs(q2)]);
    const all = [...s1.docs, ...s2.docs].map(d => d.data() as Booking);
    return Array.from(new Map(all.map(b => [b.id, b])).values());
}

