export async function transferCoins(toUid: string, toName: string, toEmail: string, amount: number, memo: string) {
    if (!db || !auth.currentUser) return;
    const fromUid = auth.currentUser.uid;
    const fromName = auth.currentUser.displayName || 'Sender';
    await runTransaction(db, async (tx) => {
        const fromRef = doc(db, USERS_COLLECTION, fromUid);
        const fromSnap = await tx.get(fromRef);
        if (!fromSnap.exists() || fromSnap.data().creditBalance < amount) throw new Error("Insufficient allocation units for handshake.");
        tx.update(fromRef, { creditBalance: increment(-amount), coinBalance: increment(-amount) });
        const txRef = doc(collection(db, TRANSACTIONS_COLLECTION));
        tx.set(txRef, sanitizeData({
            id: txRef.id, fromId: fromUid, fromName: fromName, toId: 'system', toName: 'Refractive Escrow', amount: amount, type: 'escrow_hold', memo: `Escrow for ${toName}: ${memo}`, timestamp: Date.now(), isVerified: true
        }));
        const inviteRef = doc(collection(db, 'invitations'));
        tx.set(inviteRef, sanitizeData({
            id: inviteRef.id, fromUserId: fromUid, fromName: fromName, toEmail: toEmail, toUserId: toUid, amount: amount, memo: memo, status: 'pending', type: 'credit', createdAt: Date.now()
        }));
    });
}

export async function getCoinTransactions(uid: string): Promise<CreditTransaction[]> {
    if (!db) return [];
    const q1 = query(collection(db, TRANSACTIONS_COLLECTION), where('fromId', '==', uid));
    const q2 = query(collection(db, TRANSACTIONS_COLLECTION), where('toId', '==', uid));
    const [s1, s2] = await Promise.all([getDocs(q1), getDocs(q2)]);
    const all = [...s1.docs, ...s2.docs].map(d => d.data() as CreditTransaction);
    return Array.from(new Map(all.map(tx => [tx.id, tx])).values()).sort((a, b) => b.timestamp - a.timestamp);
}

export async function deductCoins(uid: string, amount: number): Promise<UserProfile | null> {
    if (!db) return null;
    const userRef = doc(db, USERS_COLLECTION, uid);
    const preSnap = await getDoc(userRef);
    const preBalance = preSnap.data()?.creditBalance || 0;

    await updateDoc(userRef, { creditBalance: increment(-amount), coinBalance: increment(-amount), lifetimeSpent: increment(amount) });
    const postProfile = await getUserProfile(uid);
    const postBalance = postProfile?.creditBalance || 0;

    logger.info(`Neural Consumption Audit: ${amount} units refracted.`, {
        category: 'LEDGER',
        preBalance,
        postBalance,
        cost: amount
    });

    return postProfile;
}

