export async function updateCodeFile(sessionId: string, file: CodeFile) {
    if (!db) return;
    const projectRef = doc(db, CODE_PROJECTS_COLLECTION, sessionId);
    const snap = await getDoc(projectRef);
    if (!snap.exists()) return;
    const data = snap.data() as CodeProject;
    const nextFiles = data.files.map(f => (f.path || f.name) === (file.path || file.name) ? file : f);
    if (!nextFiles.some(f => (f.path || f.name) === (file.path || file.name))) nextFiles.push(file);
    await updateDoc(projectRef, { files: nextFiles, lastModified: Date.now() });
}

