export async function updateWhiteboardElement(id: string, el: WhiteboardElement) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        const ref = doc(db, WHITEBOARDS_COLLECTION, id);
        const snap = await tx.get(ref);
        const elements = snap.exists() ? (snap.data() as any).elements : [];
        const idx = elements.findIndex((e: any) => e.id === el.id);
        if (idx > -1) elements[idx] = el; else elements.push(el);
        tx.set(ref, { id, elements }, { merge: true });
    });
}

export async function deleteWhiteboardElements(id: string, elementIds: string[]) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        const ref = doc(db, WHITEBOARDS_COLLECTION, id);
        const snap = await tx.get(ref);
        if (!snap.exists()) return;
        const elements = (snap.data() as any).elements.filter((e: any) => !elementIds.includes(e.id));
        tx.update(ref, { elements });
    });
}

