export async function getCloudFileContent(fileId: string, sessionId?: string): Promise<string> {
    if (!db) return '';
    const snap = await getDoc(doc(db, CLOUD_FILES_COLLECTION, fileId));
    if (snap.exists()) {
        const data = snap.data() as any;
        if (data.isSharded) {
            let content = '';
            for (let i = 0; i < data.chunkCount; i++) {
                const chunkSnap = await getDoc(doc(db, CLOUD_FILES_COLLECTION, `${fileId}_chunk_${i}`));
                if (chunkSnap.exists()) content += (chunkSnap.data() as any).data;
            }
            return content;
        }
        return data.content || '';
    }
    return '';
}

export function subscribeToWhiteboard(id: string, callback: (els: WhiteboardElement[]) => void) {
    if (!db) return () => {};
    return onSnapshot(doc(db, WHITEBOARDS_COLLECTION, id), (snap) => {
        if (snap.exists()) callback((snap.data() as any).elements || []);
    });
}

export async function updateWhiteboardElement(id: string, el: WhiteboardElement) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        const ref = doc(db, WHITEBOARDS_COLLECTION, id);
        const snap = await tx.get(ref);
        const elements = snap.exists() ? (snap.data() as any).elements : [];
        const idx = elements.findIndex((e: any) => e.id === el.id);
        if (idx > -1) elements[idx] = el; else elements.push(el);
        tx.set(ref, { id, elements }, { merge: true });
    });
}

export async function deleteWhiteboardElements(id: string, elementIds: string[]) {
    if (!db) return;
    await runTransaction(db, async (tx) => {
        const ref = doc(db, WHITEBOARDS_COLLECTION, id);
        const snap = await tx.get(ref);
        if (!snap.exists()) return;
        const elements = (snap.data() as any).elements.filter((e: any) => !elementIds.includes(e.id));
        tx.update(ref, { elements });
    });
}

export async function saveWhiteboardSession(id: string, elements: WhiteboardElement[]) {
