export async function createGroup(name: string, visibility: 'public' | 'private'): Promise<string> {
    if (!db || !auth.currentUser) return '';
    const id = generateSecureId();
    const group: Group = {
        id,
        name,
        ownerId: auth.currentUser.uid,
        memberIds: [auth.currentUser.uid],
        createdAt: Date.now(),
