    );
};

interface SystemLogMsg {
    id: string;
    time: string;
    text: string;
    type: 'info' | 'error' | 'success' | 'warn' | 'shadow' | 'audit' | 'input' | 'output' | 'trace' | 'loop';
    meta?: any;
}

const App: React.FC = () => {
