  const handleUpdateLanguage = useCallback(async (newLang: 'en' | 'zh') => {
      setLanguage(newLang);
      if (currentUser) {
          try { await updateUserProfile(currentUser.uid, { languagePreference: newLang }); } catch(e) {}
      }
  }, [currentUser]);

  useEffect(() => {
