          <div className="flex items-center gap-3">
              {!isReadOnly && (
                  <button onClick={handleIssueAsset} disabled={isIssuing} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-50 text-white rounded-lg text-xs font-black uppercase tracking-widest shadow-lg active:scale-95">
                      {isIssuing ? <Loader2 size={14} className="animate-spin"/> : <Sparkles size={14}/>}
                      <span>Issue Asset</span>
                  </button>
              )}
          </div>
      </header>

      <div className="flex-1 flex overflow-hidden flex-col lg:flex-row">
          {!isReadOnly && (
              <div className="w-full lg:w-[400px] border-r border-slate-800 bg-slate-900/30 flex flex-col shrink-0 overflow-y-auto p-6 space-y-6 scrollbar-thin">
                  <div className="flex p-1 bg-slate-950 rounded-2xl border border-slate-800">
                      <button onClick={() => setActiveTab('details')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'details' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-50'}`}>Details</button>
                      <button onClick={() => setActiveTab('insurance')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${activeTab === 'insurance' ? 'bg-amber-600 text-white shadow-lg' : 'text-slate-50'}`}>Insurance</button>
                  </div>
                  {activeTab === 'details' ? (
                      <div className="space-y-4 animate-fade-in">
                          <input type="text" placeholder="Recipient" value={check.payee} onChange={e => setCheck({...check, payee: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white outline-none"/>
                          <div className="flex bg-slate-950 border border-slate-800 rounded-xl overflow-hidden shadow-inner">
                              <input type="number" value={check.amount || ''} onChange={e => { const val = parseFloat(e.target.value) || 0; setCheck({...check, amount: val, amountWords: numberToWords(val)}); }} className="w-full bg-transparent px-4 py-3 text-white text-lg font-black outline-none" placeholder="0.00"/>
                              <div className="bg-slate-800 p-3 text-indigo-400"><DollarSign size={20}/></div>
                          </div>
                          <div className="grid grid-cols-2 gap-4">
                              <input type="text" placeholder="Routing" value={check.routingNumber} onChange={e => setCheck({...check, routingNumber: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-xs text-indigo-300 font-mono outline-none"/>
                              <input type="text" placeholder="Account" value={check.accountNumber} onChange={e => setCheck({...check, accountNumber: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-xs text-indigo-300 font-mono outline-none"/>
                          </div>
                          <input type="text" placeholder="Memo" value={check.memo} onChange={e => setCheck({...check, memo: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white focus:ring-1 focus:ring-indigo-500 outline-none shadow-inner" />
                          <div className="grid grid-cols-2 gap-4">
                              <input type="date" value={check.date} onChange={e => setCheck({...check, date: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-xs text-white outline-none"/>
                              <input type="text" placeholder="Check #" value={check.checkNumber} onChange={e => setCheck({...check, checkNumber: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 text-xs text-white outline-none font-mono"/>
                          </div>
                      </div>
                  ) : (
                      <div className="space-y-6 animate-fade-in">
                          <div className="flex items-center justify-between p-4 bg-slate-950 border border-slate-800 rounded-2xl">
                               <div><p className="text-sm font-bold text-white">Enable Insurance</p></div>
                               <button onClick={() => setCheck({...check, isInsured: !check.isInsured})} className={`w-12 h-6 rounded-full transition-all relative ${check.isInsured ? 'bg-amber-500' : 'bg-slate-700'}`}><div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${check.isInsured ? 'right-1' : 'left-1'}`}></div></button>
                          </div>
                      </div>
                  )}
                  <div className="space-y-4 pt-4 border-t border-slate-800">
                      <button onClick={() => setShowSignPad(true)} className="w-full py-3 bg-slate-950 border border-slate-800 rounded-xl text-xs font-bold text-slate-400 hover:text-white transition-all"><PenTool size={16} className="inline mr-2"/> Sign Check</button>
                      <button onClick={handleGenerateWatermark} disabled={isGeneratingArt} className="w-full py-3 bg-slate-950 border border-slate-800 rounded-xl text-[9px] font-black uppercase text-pink-400 hover:text-white"> {isGeneratingArt ? <Loader2 size={10} className="animate-spin inline mr-2"/> : <Sparkles size={10} className="inline mr-2"/>} Neural Security Seal</button>
                  </div>
              </div>
          )}

          <div className="flex-1 bg-slate-950 flex flex-col p-8 items-center justify-center overflow-y-auto scrollbar-hide relative">
              <div ref={checkRef} style={{ transform: `scale(${zoom})`, width: '600px', height: '270px' }} className="bg-white text-black pt-10 px-10 pb-6 rounded-lg shadow-2xl relative border border-slate-300 shrink-0 overflow-hidden flex flex-col transition-all">
                  {convertedAssets.wm && <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none opacity-[0.12]"><img src={convertedAssets.wm} className="w-[180px] h-[180px] object-contain" /></div>}
                  <div className="absolute top-2 left-1/2 -translate-x-1/2 z-20 p-2 bg-white border border-black rounded-xl"><img src={qrLocalUrl || qrCodeUrl} className="w-24 h-24" alt="QR" /></div>
                  <div className="relative z-10 flex justify-between items-start">
                      <div className="space-y-0.5"><h2 className="text-sm font-black uppercase">{check.senderName || 'MEMBER'}</h2><p className="text-[8px] text-slate-600 uppercase font-bold">{userProfile?.senderAddress || 'LEDGER ADDRESS'}</p></div>
                      <div className="text-right"><p className="text-[10px] font-black uppercase">{check.checkNumber}</p><span className="text-[10px] font-mono font-bold">{check.date}</span></div>
                  </div>
                  <div className="relative z-10 mt-6 flex items-end gap-3"><span className="text-[9px] font-black uppercase mb-1">Pay to the Order of</span><div className="flex-1 border-b border-black text-xl font-serif italic pb-1 truncate">{check.payee || '____________________'}</div><div className="flex items-center bg-slate-50 border-2 border-black p-1.5 min-w-[120px]"><span className="text-lg font-bold mr-1">$</span><span className="flex-1 text-right text-xl font-mono font-black">{check.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span></div></div>
                  <div className="relative z-10 mt-2 flex items-end gap-3"><div className="flex-1 border-b border-black text-[11px] font-serif italic pb-1 uppercase">{check.amountWords || '____________________'}</div><span className="text-[10px] font-black uppercase mb-1">Dollars</span></div>
                  <div className="relative z-10 mt-auto flex justify-between items-end pb-1"><div className="flex items-end gap-2"><span className="text-[8px] font-bold uppercase">Memo</span><div className="w-48 border-b border-black text-[10px] pb-0.5 px-1 truncate">{check.memo}</div></div><div className="relative w-56 border-b-2 border-black flex flex-col items-center">{convertedAssets.sig && <img src={convertedAssets.sig} className="absolute bottom-4 w-full h-12 object-contain" />}<span className="text-[8px] font-black uppercase tracking-widest mt-1">Authorized Signature</span></div></div>
                  <div className="absolute bottom-2 left-10 right-10 flex justify-center"><div className="font-mono text-[12px] tracking-[0.4em] tubular-nums text-black">⑆ {check.routingNumber} ⑈ {check.accountNumber} ⑈ {check.checkNumber}</div></div>
              </div>
          </div>
      </div>
      {showSignPad && (
          <div className="fixed inset-0 z-[150] bg-slate-950/95 flex items-center justify-center p-6 animate-fade-in">
              <div className="w-full max-w-2xl bg-white rounded-3xl overflow-hidden shadow-2xl border-8 border-indigo-600">
                  <div className="p-6 bg-indigo-600 flex justify-between items-center text-white"><h3 className="font-black uppercase tracking-widest flex items-center gap-2"><PenTool size={20}/> Signature Pad</h3><button onClick={() => setShowSignPad(false)}><X size={24}/></button></div>
                  <div className="h-64 bg-white relative"><Whiteboard backgroundColor="#ffffff" initialColor="#000000" onChange={() => {}} onBack={() => setShowSignPad(false)}/></div>
                  <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-end gap-3"><button onClick={() => setShowSignPad(false)} className="px-6 py-2 text-sm font-bold text-slate-400">Cancel</button><button onClick={() => { const canvas = document.getElementById('whiteboard-canvas-core') as HTMLCanvasElement; if (canvas) handleSaveSignature(canvas.toDataURL()); }} className="px-8 py-2 bg-indigo-600 text-white rounded-xl font-bold text-sm shadow-lg">Adopt</button></div>
              </div>
          </div>
      )}
      {showHistory && (
        <div className="fixed inset-0 z-[150] bg-slate-950/95 flex items-center justify-center p-4">
          <div className="w-full max-w-4xl bg-slate-900 border border-slate-700 rounded-[2.5rem] overflow-hidden flex flex-col h-full max-h-[90vh]">
            <div className="p-6 bg-indigo-600 flex justify-between items-center text-white"><h3 className="font-black uppercase flex items-center gap-2"><History size={20}/> Registry</h3><button onClick={() => setShowHistory(false)}><X size={24}/></button></div>
            <div className="flex-1 overflow-y-auto p-6 space-y-4">
              {history.map(h => (
                <div key={h.id} onClick={() => { handleSwitchToId(h.id); setShowHistory(false); }} className="bg-slate-950 border border-slate-800 p-4 rounded-2xl flex items-center justify-between cursor-pointer hover:border-indigo-500/50 transition-all">
                  <div className="flex items-center gap-4"><div className="p-3 bg-indigo-900/30 text-indigo-400 rounded-xl"><Wallet size={20}/></div><div><p className="text-sm font-bold text-white">#{h.checkNumber} - {h.payee}</p><p className="text-[10px] text-slate-500 font-mono">{h.date}</p></div></div>
                  <div className="text-right">
                    <p className="text-lg font-black text-indigo-400">${h.amount.toLocaleString()}</p>
                    {h.isVerified && <SecurityIcon size={14} className="text-emerald-500 inline ml-1"/>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      {showManual && (
          <div className="fixed inset-0 z-[150] bg-slate-950/95 flex items-center justify-center p-4 animate-fade-in"><div className="w-full max-w-4xl bg-white rounded-[2.5rem] overflow-hidden flex flex-col h-full max-h-[90vh]"><div className="p-6 bg-indigo-600 flex justify-between items-center"><h3 className="text-white font-black uppercase flex items-center gap-2">< BookOpen size={20}/> Manual</h3><button onClick={() => setShowManual(false)} className="text-white/60 hover:text-white transition-colors"><X size={24}/></button></div><div className="flex-1 overflow-y-auto"><MarkdownView content={FINANCE_LAB_MANUAL} initialTheme="light" showThemeSwitcher={false} /></div></div></div>
      )}
      {showShareModal && (<ShareModal isOpen={true} onClose={() => setShowShareModal(false)} link={shareLink || ''} title={`Check #${check.checkNumber}`} onShare={async () => {}} />)}
    </div>
  );
};

export default CheckDesigner;
